import re
import os
import sys
import argparse
from PIL import Image

def convert_hexdump_to_png(input_path, output_path, width=640, height=480):
    raw_bytes = bytearray()
    hex_line_pattern = re.compile(r'^[0-9a-fA-F]{8}\s+((?:[0-9a-fA-F]{2}\s*){1,16})')
    
    is_grayscale = False

    try:
        with open(input_path, 'r') as f:
            first_line = f.readline()
            # Detect type from the header line generated by your log_breath/print_mem
            if "Grayscale" in first_line:
                is_grayscale = True
            
            f.seek(0) # Reset to start to parse hex
            for line in f:
                match = hex_line_pattern.match(line)
                if match:
                    hex_values = match.group(1).split()
                    for val in hex_values:
                        raw_bytes.append(int(val, 16))

        # Determine expected size
        # Grayscale = 1 byte per pixel, BGR = 3 bytes per pixel
        channels = 1 if is_grayscale else 3
        expected_size = width * height * channels
        
        if len(raw_bytes) < expected_size:
            print(f"  [!] Warning: {input_path} has insufficient data ({len(raw_bytes)} bytes). Expected {expected_size}.")
            return False
        
        data = raw_bytes[:expected_size]
        
        if is_grayscale:
            # Process as Grayscale (8-bit)
            img = Image.frombytes('L', (width, height), bytes(data))
        else:
            # Process as BGR and convert to RGB
            img = Image.frombytes('RGB', (width, height), bytes(data))
            b, g, r = img.split()
            img = Image.merge('RGB', (r, g, b))
        
        img.save(output_path)
        return True
    except Exception as e:
        print(f"  [!] Error processing {input_path}: {e}")
        return False

def main():
    parser = argparse.ArgumentParser(description="Convert BGR hexdump .txt files to PNG images.")
    parser.add_argument("directory", help="Path to the directory containing hexdump .txt files")
    parser.add_argument("--width", type=int, default=640, help="Image width (default: 640)")
    parser.add_argument("--height", type=int, default=480, help="Image height (default: 480)")
    
    args = parser.parse_args()

    if not os.path.isdir(args.directory):
        print(f"Error: {args.directory} is not a valid directory.")
        sys.exit(1)

    output_dir = os.path.join(args.directory, "converted_pngs")
    if not os.path.exists(output_dir):
        os.makedirs(output_dir)

    files = [f for f in os.listdir(args.directory) if f.endswith('.txt')]
    
    if not files:
        print(f"No .txt files found in {args.directory}")
        return

    print(f"Processing {len(files)} files from: {args.directory}")
    for filename in files:
        input_file = os.path.join(args.directory, filename)
        output_file = os.path.join(output_dir, filename.replace('.txt', '.png'))
        
        if convert_hexdump_to_png(input_file, output_file, args.width, args.height):
            print(f"  [+] Converted: {filename} -> {os.path.basename(output_file)}")

if __name__ == "__main__":
    main()